def matches(dp, f, files):
    p = dp[len("./") :] + "/" + f
    p = p.replace("\\", "/")
    return p in files


def main():
    upstream_root = clone_repo("https://github.com/abseil/abseil-cpp.git", "20240116.0")
    wpilib_root = get_repo_root()
    wpiutil = os.path.join(wpilib_root, "wpiutil")

    # Apply patches to upstream Git repo
    os.chdir(upstream_root)
    for f in []:
        git_am(os.path.join(wpilib_root, "upstream_utils/abseil_patches", f))

    # Delete old install
    for d in [
        "src/main/native/thirdparty/abseil/src",
        "src/main/native/thirdparty/abseil/include",
    ]:
        shutil.rmtree(os.path.join(wpiutil, d), ignore_errors=True)

    # Copy source files into allwpilib
    src_files = walk_if(".", lambda dp, f: matches(dp, f, abseil_sources))
    os.chdir(os.path.join(upstream_root))
    copy_to(src_files, os.path.join(wpiutil, "src/main/native/thirdparty/abseil/src"))

    # Copy header files into allwpilib
    os.chdir(upstream_root)
    include_files = walk_if(".", lambda dp, f: matches(dp, f, abseil_headers))
    os.chdir(os.path.join(upstream_root))
    copy_to(
        include_files,
        os.path.join(wpiutil, "src/main/native/thirdparty/abseil/include"),
    )

    # Copy test files into allwpilib
    def test_matcher(dp, f):
        if f.endswith("_test.cc"):
            print("Keeping", f)
            return True
        return False

    os.chdir(upstream_root)
    include_files = walk_if(".", test_matcher)
    os.chdir(os.path.join(upstream_root))
    copy_to(
        include_files,
        os.path.join(wpiutil, "src/test/native/abseil/include"),
    )




if __name__ == "__main__":
    main()
